app/services/bill_totals.py :: quantize_money
def quantize_money(value: Decimal) -> Decimal:
    return value.quantize(MONEY_QUANTIZE, rounding=ROUND_HALF_UP)

app/services/bill_totals.py :: sum_money
def sum_money(values: Sequence[Decimal]) -> Decimal:
    return quantize_money(sum(values, Decimal("0")))

app/services/bill_totals.py :: compute_subtotal_from_items
def compute_subtotal_from_items(item_totals: Sequence[Decimal]) -> Decimal:
    return sum_money(item_totals)

app/services/bill_totals.py :: compute_bill_total
def compute_bill_total(
    *,
    subtotal: Decimal,
    tax: Decimal,
    service_fee: Decimal,
) -> Decimal:
    """Platform total: items + tax + service fee. Tip stays on the receipt subtotal."""
    return quantize_money(subtotal + tax + service_fee)

app/services/bill_totals.py :: compute_service_fee
def compute_service_fee(
    *,
    subtotal: Decimal,
    fee_type: str,
    fee_percentage: Decimal | None,
    flat_amount: Decimal,
    default_percentage: Decimal,
) -> Decimal:
    if fee_type == "flat":
        return quantize_money(flat_amount)

    if fee_type == "percentage":
        percentage = fee_percentage if fee_percentage is not None else default_percentage
        return quantize_money(subtotal * percentage / Decimal("100"))

    return Decimal("0")

app/services/bill_totals.py :: member_proportion
def member_proportion(member_subtotal: Decimal, bill_subtotal: Decimal) -> Decimal:
    if bill_subtotal <= 0:
        return Decimal("0")
    return member_subtotal / bill_subtotal

app/services/bill_totals.py :: distribute_proportionally
def distribute_proportionally(portion: Decimal, proportion: Decimal) -> Decimal:
    return quantize_money(proportion * portion)

app/services/bill_totals.py :: compute_member_total_owed
def compute_member_total_owed(
    *,
    member_subtotal: Decimal,
    tax_share: Decimal,
    tip_share: Decimal,
    fee_share: Decimal,
    is_host: bool,
) -> Decimal:
    if is_host:
        return Decimal("0")
    return quantize_money(member_subtotal + tax_share + tip_share + fee_share)

app/services/bill_totals.py :: calculate_assignment_amount_owed
def calculate_assignment_amount_owed(
    share_type: str,
    share_value: Decimal,
    item_total_price: Decimal,
    assignment_count: int,
) -> Decimal:
    if share_type == "equal":
        if assignment_count <= 0:
            return Decimal("0")
        return quantize_money(item_total_price / assignment_count)

    if share_type == "percentage":
        return quantize_money(item_total_price * share_value / Decimal("100"))

    if share_type == "fixed":
        return quantize_money(share_value)

    raise ValueError(f"Unknown share_type: {share_type}")
